sys_script_include.script:
var ITSMGroupAssignment = Class.create();
ITSMGroupAssignment.prototype = {
    initialize: function() {},
    categoryGroupMap: {
        'Hardware': 'Hardware Support',
        'Software': 'Software Support',
        'Network': 'Network Support',
        'Others': 'Others Support'
    },
    l2GroupName: 'L2 Support Team',

    assignL1Group: function(gr) {
        if (!gr || !gr.category) {
            gs.error('ITSMGroupAssignment: No category provided for incident ' + gr.number);
            return false;
        }
        var category = gr.getDisplayValue('category');
        var groupName = this.categoryGroupMap[category];
        if (!groupName) {
            groupName = 'Others Support';
            gs.warn('ITSMGroupAssignment: Unknown category "' + category + '" for incident ' + gr.number + '. Assigning to Others Support.');
        }
        var groupGr = new GlideRecord('sys_user_group');
        if (groupGr.get('name', groupName)) {
            gr.assignment_group = groupGr.getUniqueValue();
            gr.assigned_to = '';
            gs.info('ITSMGroupAssignment: Incident ' + gr.number + ' assigned to group: ' + groupName);
            return true;
        } else {
            gs.error('ITSMGroupAssignment: Group "' + groupName + '" not found for incident ' + gr.number);
            return false;
        }
    },

    escalateToL2: function(gr) {
        if (!gr) return false;
        var l2Group = new GlideRecord('sys_user_group');
        if (l2Group.get('name', this.l2GroupName)) {
            gr.setValue('u_original_l1_group', gr.getValue('assignment_group'));
            gr.assignment_group = l2Group.getUniqueValue();
            gr.escalation = 2;
            gr.work_notes = 'Incident escalated to L2 Support Team.\nOriginal L1 Group: ' + gr.getDisplayValue('u_original_l1_group');
            gs.info('ITSMGroupAssignment: Incident ' + gr.number + ' escalated to L2 Support Team');
            return true;
        } else {
            gs.error('ITSMGroupAssignment: L2 Support Team group not found');
            return false;
        }
    },

    getGroupForCategory: function(category) {
        var groupName = this.categoryGroupMap[category] || 'Others Support';
        var groupGr = new GlideRecord('sys_user_group');
        if (groupGr.get('name', groupName)) {
            return groupGr.getUniqueValue();
        }
        return '';
    },

    getCategories: function() {
        var categories = [];
        for (var cat in this.categoryGroupMap) {
            if (this.categoryGroupMap.hasOwnProperty(cat)) {
                categories.push(cat);
            }
        }
        return categories;
    },
    type: 'ITSMGroupAssignment'
};

var ITSMNotificationUtils = Class.create();
ITSMNotificationUtils.prototype = {
    initialize: function() {},
    sendIncidentCreatedNotification: function(gr) {
        if (!gr) return;
        gr.setEvent('incident.created', gr.getUniqueValue(), 'Incident ' + gr.number + ' has been created');
        gs.info('ITSMNotificationUtils: Notification sent for new incident ' + gr.number);
    },
    sendAssignedNotification: function(gr, previousGroup) {
        if (!gr) return;
        var currentGroup = gr.getValue('assignment_group');
        if (currentGroup && currentGroup !== previousGroup) {
            gr.setEvent('incident.assigned', gr.getUniqueValue(), 'Incident ' + gr.number + ' has been assigned to ' + gr.getDisplayValue('assignment_group'));
            gs.info('ITSMNotificationUtils: Assignment notification sent for incident ' + gr.number);
        }
    },
    sendStateChangeNotification: function(gr, previousState) {
        if (!gr) return;
        var currentState = gr.getValue('state');
        if (currentState !== previousState) {
            var stateLabel = this.getStateLabel(currentState);
            var prevLabel = this.getStateLabel(previousState);
            gr.setEvent('incident.state_changed', gr.getUniqueValue(), 'Incident ' + gr.number + ' state changed from "' + prevLabel + '" to "' + stateLabel + '"');
            gs.info('ITSMNotificationUtils: State change notification sent for incident ' + gr.number + ': ' + prevLabel + ' -> ' + stateLabel);
        }
    },
    sendEscalationNotification: function(gr) {
        if (!gr) return;
        gr.setEvent('incident.escalated', gr.getUniqueValue(), 'Incident ' + gr.number + ' has been escalated to L2 Support Team');
        gs.info('ITSMNotificationUtils: Escalation notification sent for incident ' + gr.number);
    },
    getStateLabel: function(state) {
        var stateMap = { 1: 'New', 2: 'In Progress', 3: 'On Hold', 6: 'Resolved', 7: 'Closed' };
        return stateMap[state] || 'Unknown (' + state + ')';
    },
    type: 'ITSMNotificationUtils'
};

var ITSMEmailParser = Class.create();
ITSMEmailParser.prototype = {
    initialize: function() {},
    parseAndCreateIncident: function(email, incident) {
        if (!email || !incident) return false;
        try {
            incident.short_description = this.extractSubject(email.subject);
            incident.description = this.extractDescription(email.body_text, email.body_html);
            incident.category = this.extractCategory(email.subject + ' ' + email.body_text);
            var subcategory = this.extractSubCategory(email.subject + ' ' + email.body_text, incident.category);
            if (subcategory) incident.subcategory = subcategory;
            var urgency = this.extractUrgency(email.subject + ' ' + email.body_text);
            if (urgency) { incident.urgency = urgency; incident.impact = urgency; }
            incident.caller_id = this.findCaller(email.from);
            incident.contact_type = 'email';
            incident.u_source = 'Email';
            gs.info('ITSMEmailParser: Successfully parsed email from ' + email.from + ' for incident creation');
            return true;
        } catch (e) {
            gs.error('ITSMEmailParser: Error parsing email - ' + e.message);
            return false;
        }
    },
    extractSubject: function(subject) {
        if (!subject) return 'No Subject - Incident created from email';
        subject = subject.replace(/^(RE|FWD|FW):\s*/gi, '').trim();
        if (subject.length > 160) subject = subject.substring(0, 157) + '...';
        return subject;
    },
    extractDescription: function(bodyText, bodyHtml) {
        var description = bodyText || '';
        description = description.replace(/^>.*$/gm, '').trim();
        var sigIndex = description.indexOf('-- ');
        if (sigIndex > 0) description = description.substring(0, sigIndex).trim();
        var replyIndex = description.search(/From:|Sent:|To:|Cc:/);
        if (replyIndex > 0) description = description.substring(0, replyIndex).trim();
        return description || 'No description provided.';
    },
    extractCategory: function(content) {
        if (!content) return 'Others';
        var categories = ['Hardware', 'Software', 'Network', 'Others'];
        var catMatch = content.match(/\[?[Cc]ategory:\s*(\w+)\]?/);
        if (catMatch && catMatch[1]) {
            var found = catMatch[1];
            found = found.charAt(0).toUpperCase() + found.slice(1).toLowerCase();
            if (categories.indexOf(found) >= 0) return found;
        }
        var keywordMap = {
            'Hardware': ['laptop', 'desktop', 'printer', 'monitor', 'keyboard', 'mouse', 'hardware', 'device', 'server'],
            'Software': ['software', 'application', 'app', 'os', 'windows', 'linux', 'office', 'excel', 'word', 'outlook', 'error', 'bug', 'crash'],
            'Network': ['network', 'internet', 'wifi', 'vpn', 'router', 'switch', 'connectivity', 'connection', 'slow', 'speed']
        };
        var lowerContent = content.toLowerCase();
        for (var cat in keywordMap) {
            for (var i = 0; i < keywordMap[cat].length; i++) {
                var regex = new RegExp('\\b' + keywordMap[cat][i] + '\\b', 'i');
                if (regex.test(lowerContent)) return cat;
            }
        }
        return 'Others';
    },
    extractSubCategory: function(content, category) {
        if (!content || !category) return null;
        var subcategoryMap = {
            'Hardware': ['laptop', 'desktop', 'printer', 'server', 'monitor', 'keyboard', 'mouse'],
            'Software': ['os', 'office', 'erp', 'crm', 'windows', 'linux', 'excel', 'word', 'outlook'],
            'Network': ['router', 'switch', 'firewall', 'vpn', 'wifi'],
            'Others': ['general', 'account', 'inquiry', 'password']
        };
        var subcategories = subcategoryMap[category];
        if (!subcategories) return null;
        var lowerContent = content.toLowerCase();
        for (var i = 0; i < subcategories.length; i++) {
            var regex = new RegExp('\\b' + subcategories[i] + '\\b', 'i');
            if (regex.test(lowerContent)) return subcategories[i].charAt(0).toUpperCase() + subcategories[i].slice(1).toLowerCase();
        }
        return null;
    },
    extractUrgency: function(content) {
        if (!content) return null;
        var urgencyMatch = content.match(/\[?[Uu]rgency:\s*(High|Medium|Low|Critical|1|2|3)\]/);
        if (urgencyMatch) {
            var val = urgencyMatch[1].toLowerCase();
            if (val === 'critical' || val === 'high' || val === '1') return 1;
            if (val === 'medium' || val === '2') return 2;
            if (val === 'low' || val === '3') return 3;
        }
        var urgentMarkers = (content.match(/!/g) || []).length;
        if (urgentMarkers >= 3) return 1;
        return null;
    },
    findCaller: function(fromAddress) {
        if (!fromAddress) return '';
        var user = new GlideRecord('sys_user');
        if (user.get('email', fromAddress)) return user.getUniqueValue();
        var parts = fromAddress.split('@');
        if (parts.length > 0 && user.get('user_name', parts[0])) return user.getUniqueValue();
        gs.warn('ITSMEmailParser: No user found for email address: ' + fromAddress);
        return '';
    },
    type: 'ITSMEmailParser'
};

var ProblemUtils = Class.create();
ProblemUtils.prototype = {
    initialize: function() {},
    isL2Agent: function() {
        if (gs.hasRole('admin')) return true;
        if (gs.hasRole('itsm_l2_agent')) return true;
        var l2Group = new GlideRecord('sys_user_group');
        if (l2Group.get('name', 'L2 Support Team')) {
            var member = new GlideRecord('sys_user_grmember');
            member.addQuery('user', gs.getUserID());
            member.addQuery('group', l2Group.getUniqueValue());
            member.query();
            if (member.hasNext()) return true;
        }
        return false;
    },
    createProblemFromIncident: function(incidentGr) {
        if (!incidentGr) return {success: false, error: 'No incident provided'};
        if (!this.isL2Agent()) return {success: false, error: 'Only L2 Support Team members can create problems'};
        try {
            var problemGr = new GlideRecord('problem');
            problemGr.initialize();
            problemGr.short_description = 'Problem: ' + incidentGr.getValue('short_description');
            problemGr.description = this.buildProblemDescription(incidentGr);
            problemGr.category = incidentGr.getValue('category');
            problemGr.subcategory = incidentGr.getValue('subcategory');
            problemGr.urgency = incidentGr.getValue('urgency');
            problemGr.impact = incidentGr.getValue('impact');
            var originalGroup = incidentGr.getValue('u_original_l1_group');
            if (originalGroup) problemGr.assignment_group = originalGroup;
            else problemGr.assignment_group = incidentGr.getValue('assignment_group');
            problemGr.assigned_to = gs.getUserID();
            problemGr.setValue('u_source_incident', incidentGr.getUniqueValue());
            var problemSysId = problemGr.insert();
            if (problemSysId) {
                this.linkIncidentToProblem(incidentGr.getUniqueValue(), problemSysId);
                this.addProblemToIncident(incidentGr.getUniqueValue(), problemSysId);
                this.sendProblemCreatedNotification(problemGr);
                return {success: true, number: problemGr.number, sys_id: problemSysId, message: 'Problem ' + problemGr.number + ' has been created successfully.'};
            } else {
                return {success: false, error: 'Failed to create problem record'};
            }
        } catch (e) {
            return {success: false, error: e.message};
        }
    },
    buildProblemDescription: function(incidentGr) {
        var description = '=== Problem created from Incident ' + incidentGr.number + ' ===\n\n';
        description += 'Original Incident Details:\n';
        description += '  Short Description: ' + incidentGr.getValue('short_description') + '\n';
        description += '  Category/Subcategory: ' + incidentGr.getDisplayValue('category') + ' / ' + incidentGr.getDisplayValue('subcategory') + '\n';
        description += '  Caller: ' + incidentGr.getDisplayValue('caller_id') + '\n';
        description += '  Urgency/Impact: ' + incidentGr.getDisplayValue('urgency') + ' / ' + incidentGr.getDisplayValue('impact') + '\n';
        description += '  Assignment Group: ' + incidentGr.getDisplayValue('assignment_group') + '\n\n';
        description += 'Original Description:\n' + incidentGr.getValue('description') + '\n\n';
        description += '=== End of Incident Details ===\n\n';
        return description;
    },
    linkIncidentToProblem: function(incidentSysId, problemSysId) {
        var incGr = new GlideRecord('incident');
        if (incGr.get(incidentSysId)) {
            incGr.problem_id = problemSysId;
            var problemGr = new GlideRecord('problem');
            problemGr.get(problemSysId);
            incGr.work_notes = '\n[Problem Created] Problem ' + problemGr.number + ' has been created by ' + gs.getUserDisplayName() + ' to track this issue.';
            incGr.update();
        }
    },
    addProblemToIncident: function(incidentSysId, problemSysId) {
        var taskRel = new GlideRecord('task_relates_to');
        taskRel.initialize();
        taskRel.task_to = problemSysId;
        taskRel.task_from = incidentSysId;
        taskRel.type = 'problem_from_incident';
        taskRel.insert();
    },
    sendProblemCreatedNotification: function(problemGr) {
        if (!problemGr) return;
        try {
            problemGr.setEvent('problem.created', problemGr.getUniqueValue(), 'Problem ' + problemGr.number + ' has been created from incident');
        } catch (e) {
            gs.error('ProblemUtils: Error sending notification - ' + e.message);
        }
    },
    sendProblemStateChangeNotification: function(problemGr, previousState) {
        if (!problemGr) return;
        try {
            var currentState = problemGr.getValue('state');
            if (currentState !== previousState) {
                problemGr.setEvent('problem.state_changed', problemGr.getUniqueValue(), 'Problem ' + problemGr.number + ' state changed');
            }
        } catch (e) {
            gs.error('ProblemUtils: Error sending state change notification - ' + e.message);
        }
    },
    getProblemStates: function() {
        return { '1': 'New', '2': 'Under Investigation', '3': 'Root Cause Identified', '4': 'Known Error', '5': 'Resolution Identified', '6': 'Resolved', '7': 'Closed' };
    },
    type: 'ProblemUtils'
};

var ChangeUtils = Class.create();
ChangeUtils.prototype = {
    initialize: function() {},
    canCreateChange: function() {
        if (gs.hasRole('admin') || gs.hasRole('change_manager') || gs.hasRole('itsm_l2_agent') || gs.hasRole('itsm_l3_agent')) return true;
        var userGroups = this.getUserGroups();
        for (var i = 0; i < userGroups.length; i++) {
            var gr = new GlideRecord('sys_user_group');
            if (gr.get(userGroups[i]) && (gr.getValue('type') === 'itsm_l2_group' || gr.getValue('type') === 'itsm_l3_group')) return true;
        }
        return false;
    },
    getUserGroups: function() {
        var groups = [];
        var gr = new GlideRecord('sys_user_grmember');
        gr.addQuery('user', gs.getUserID());
        gr.query();
        while (gr.next()) groups.push(gr.getValue('group'));
        return groups;
    },
    isInfrastructureChange: function(changeGr) {
        if (!changeGr) return false;
        var type = changeGr.getValue('type');
        if (type === 'infrastructure' || type === 'Infrastructure') return true;
        var assignmentGroup = changeGr.getDisplayValue('assignment_group');
        if (assignmentGroup && assignmentGroup.toLowerCase().indexOf('infrastructure') >= 0) return true;
        return false;
    },
    isHighPriority: function(changeGr) {
        if (!changeGr) return false;
        var priority = changeGr.getValue('priority');
        return (priority === '1' || priority === '2');
    },
    createChangeFromProblem: function(problemGr, params) {
        if (!problemGr) return {success: false, error: 'No problem provided'};
        if (!this.canCreateChange()) return {success: false, error: 'Only L2 or L3 support members can create changes'};
        try {
            var changeGr = new GlideRecord('change_request');
            changeGr.initialize();
            changeGr.short_description = 'Change: ' + problemGr.getValue('short_description');
            changeGr.description = this.buildChangeDescription(problemGr);
            changeGr.category = problemGr.getValue('category');
            changeGr.subcategory = problemGr.getValue('subcategory');
            changeGr.urgency = problemGr.getValue('urgency');
            changeGr.impact = problemGr.getValue('impact');
            changeGr.priority = this.calculatePriority(parseInt(problemGr.getValue('urgency') || 2), parseInt(problemGr.getValue('impact') || 2));
            changeGr.type = (params && params.type) ? params.type : 'Infrastructure';
            if (changeGr.getValue('type') === 'Infrastructure') changeGr.assignment_group = this.findGroupByName('Change Management - Infrastructure');
            else changeGr.assignment_group = this.findGroupByName('Change Management - Application');
            if (params && params.start_date) changeGr.setValue('start_date', params.start_date);
            else { var gdt = new GlideDateTime(); gdt.addDays(7); changeGr.setValue('start_date', gdt); }
            if (params && params.end_date) changeGr.setValue('end_date', params.end_date);
            else { var gdtEnd = new GlideDateTime(); gdtEnd.addDays(8); changeGr.setValue('end_date', gdtEnd); }
            changeGr.setValue('u_source_problem', problemGr.getUniqueValue());
            if (changeGr.getValue('priority') <= 2) this.setCABForChange(changeGr);
            var changeSysId = changeGr.insert();
            if (changeSysId) {
                this.linkProblemToChange(problemGr.getUniqueValue(), changeSysId);
                if (this.isInfrastructureChange(changeGr)) this.onInfrastructureChangeCreated(changeGr);
                this.sendChangeCreatedNotification(changeGr);
                return {success: true, number: changeGr.number, sys_id: changeSysId, message: 'Change ' + changeGr.number + ' has been created successfully.'};
            } else {
                return {success: false, error: 'Failed to create change record'};
            }
        } catch (e) {
            return {success: false, error: e.message};
        }
    },
    calculatePriority: function(urgency, impact) {
        var matrix = {'1,1':1,'1,2':2,'1,3':3,'2,1':2,'2,2':3,'2,3':4,'3,1':3,'3,2':4,'3,3':5};
        return matrix[urgency + ',' + impact] || 3;
    },
    buildChangeDescription: function(problemGr) {
        return '=== Change created from Problem ' + problemGr.number + ' ===\n\nOriginal Problem Details:\n  Short Description: ' + problemGr.getValue('short_description') + '\n  Category/Subcategory: ' + problemGr.getDisplayValue('category') + ' / ' + problemGr.getDisplayValue('subcategory') + '\n  Priority: ' + problemGr.getDisplayValue('priority') + '\n\nOriginal Problem Description:\n' + problemGr.getValue('description') + '\n\n=== End of Problem Details ===\n\n=== Change Implementation Plan ===\n[To be filled by change implementer]\n\n=== Rollback Plan ===\n[To be filled by change implementer]\n';
    },
    findGroupByName: function(name) {
        var gr = new GlideRecord('sys_user_group');
        if (gr.get('name', name)) return gr.getUniqueValue();
        return '';
    },
    setCABForChange: function(changeGr) {
        changeGr.setValue('cab_required', true);
        changeGr.setValue('cab_recommendation', 'Required due to high priority');
        var cabGroup = this.findGroupByName('Change Management - Infrastructure');
        if (cabGroup) changeGr.setValue('cab_group', cabGroup);
    },
    linkProblemToChange: function(problemSysId, changeSysId) {
        var problemGr = new GlideRecord('problem');
        if (problemGr.get(problemSysId)) {
            problemGr.setValue('u_change', changeSysId);
            problemGr.work_notes = '\n[Change Created] Change has been created by ' + gs.getUserDisplayName() + ' to implement the resolution.';
            problemGr.update();
        }
    },
    onInfrastructureChangeCreated: function(changeGr) {
        changeGr.state = 2;
        changeGr.update();
        gs.info('ChangeUtils: Infrastructure change ' + changeGr.number + ' moved to Assess state');
    },
    autoCreateChangeTasks: function(changeGr) {
        if (!this.isInfrastructureChange(changeGr)) return false;
        try {
            var task1 = new GlideRecord('change_task');
            task1.initialize();
            task1.change_request = changeGr.getUniqueValue();
            task1.short_description = 'Pre-implementation Environment Check';
            task1.description = 'Verify that the production environment is ready for the change.\n\nChecklist:\n1. Verify system backups are current\n2. Check resource availability (CPU, Memory, Disk)\n3. Verify network connectivity\n4. Confirm all prerequisites are met\n5. Notify stakeholders about the upcoming change';
            task1.assignment_group = changeGr.getValue('assignment_group');
            task1.state = 1;
            task1.priority = changeGr.getValue('priority');
            var task1Id = task1.insert();
            var task2 = new GlideRecord('change_task');
            task2.initialize();
            task2.change_request = changeGr.getUniqueValue();
            task2.short_description = 'Post-implementation Verification';
            task2.description = 'Verify that the change has been implemented successfully.\n\nChecklist:\n1. Verify the change was applied correctly\n2. Run system health checks\n3. Validate functionality with test cases\n4. Check for any error logs\n5. Confirm with stakeholders that the change is successful\n6. Document any issues encountered';
            task2.assignment_group = changeGr.getValue('assignment_group');
            task2.state = 1;
            task2.priority = changeGr.getValue('priority');
            var task2Id = task2.insert();
            changeGr.work_notes = 'Auto-created 2 change tasks for infrastructure change:\n- Pre-implementation Environment Check\n- Post-implementation Verification';
            return true;
        } catch (e) {
            gs.error('ChangeUtils: Error creating change tasks - ' + e.message);
            return false;
        }
    },
    sendChangeCreatedNotification: function(changeGr) {
        try { changeGr.setEvent('change.created', changeGr.getUniqueValue(), 'Change ' + changeGr.number + ' has been created'); } catch (e) {}
    },
    sendChangeStateChangeNotification: function(changeGr, previousState) {
        try {
            var currentState = changeGr.getValue('state');
            if (currentState !== previousState) changeGr.setEvent('change.state_changed', changeGr.getUniqueValue(), 'Change ' + changeGr.number + ' state changed');
        } catch (e) {}
    },
    getChangeStates: function() { return {'1':'New','2':'Assess','3':'Authorize','4':'Scheduled','5':'Implement','6':'Review','7':'Closed','-1':'Cancelled'}; },
    type: 'ChangeUtils'
};

var KnowledgeUtils = Class.create();
KnowledgeUtils.prototype = {
    initialize: function() {},
    getTechnicalKbSysId: function() { return this.getKbSysIdByName('Technical Knowledge Base'); },
    getEmployeeKbSysId: function() { return this.getKbSysIdByName('Employee Knowledge Base'); },
    getKbSysIdByName: function(name) {
        var gr = new GlideRecord('kb_knowledge_base');
        if (gr.get('name', name)) return gr.getUniqueValue();
        return '';
    },
    canViewKb: function(userId, kbSysId) {
        if (gs.hasRole('admin')) return true;
        var kbGr = new GlideRecord('kb_knowledge_base');
        if (!kbGr.get(kbSysId)) return false;
        var kbName = kbGr.getValue('name');
        if (kbName === 'Employee Knowledge Base') return true;
        if (kbName === 'Technical Knowledge Base') return this.isTechnicalUser(userId);
        return this.isTechnicalUser(userId);
    },
    isTechnicalUser: function(userId) {
        if (gs.hasRole('admin') || gs.hasRole('itsm_l1_agent') || gs.hasRole('itsm_l2_agent') || gs.hasRole('itsm_l3_agent') || gs.hasRole('knowledge_admin') || gs.hasRole('knowledge_manager')) return true;
        var gr = new GlideRecord('sys_user_grmember');
        gr.addQuery('user', userId || gs.getUserID());
        gr.query();
        while (gr.next()) {
            var groupGr = new GlideRecord('sys_user_group');
            if (groupGr.get(gr.getValue('group'))) {
                var type = groupGr.getValue('type');
                if (type === 'itsm_l1_group' || type === 'itsm_l2_group' || type === 'itsm_l3_group') return true;
            }
        }
        return false;
    },
    requiresPublishApproval: function(kbSysId) {
        var kbGr = new GlideRecord('kb_knowledge_base');
        if (!kbGr.get(kbSysId)) return false;
        return kbGr.getValue('name') === 'Technical Knowledge Base';
    },
    type: 'KnowledgeUtils'
};

var SLAUtils = Class.create();
SLAUtils.prototype = {
    initialize: function() {},
    SLA_CONFIG: {
        response: {1:{name:'Response SLA - Critical',duration:900},2:{name:'Response SLA - High',duration:3600},3:{name:'Response SLA - Medium',duration:14400},4:{name:'Response SLA - Low',duration:28800},5:{name:'Response SLA - Planning',duration:57600}},
        resolution: {1:{name:'Resolution SLA - Critical',duration:3600},2:{name:'Resolution SLA - High',duration:14400},3:{name:'Resolution SLA - Medium',duration:86400},4:{name:'Resolution SLA - Low',duration:172800},5:{name:'Resolution SLA - Planning',duration:345600}}
    },
    NOTIFICATION_PERCENTAGES: [75, 90, 100],
    getResponseSlaDuration: function(priority) { var config = this.SLA_CONFIG.response[priority]; return config ? config.duration : this.SLA_CONFIG.response[5].duration; },
    getResolutionSlaDuration: function(priority) { var config = this.SLA_CONFIG.resolution[priority]; return config ? config.duration : this.SLA_CONFIG.resolution[5].duration; },
    formatDuration: function(seconds) {
        if (seconds < 60) return seconds + ' sec';
        if (seconds < 3600) return Math.floor(seconds / 60) + ' min';
        if (seconds < 86400) return Math.floor(seconds / 3600) + ' hours';
        return Math.floor(seconds / 86400) + ' days ' + Math.floor((seconds % 86400) / 3600) + ' hours';
    },
    startResponseSla: function(incidentGr) { return this.startSla(incidentGr, 'response'); },
    startResolutionSla: function(incidentGr) { return this.startSla(incidentGr, 'resolution'); },
    startSla: function(incidentGr, slaType) {
        if (!incidentGr || !slaType) return {success: false, error: 'Missing required parameters'};
        try {
            var priority = parseInt(incidentGr.getValue('priority') || 3);
            var config = slaType === 'response' ? this.SLA_CONFIG.response[priority] : this.SLA_CONFIG.resolution[priority];
            if (!config) return {success: false, error: 'No SLA configuration for priority ' + priority};
            var existingSla = new GlideRecord('task_sla');
            existingSla.addQuery('task', incidentGr.getUniqueValue());
            existingSla.addQuery('sla_type', slaType);
            existingSla.addQuery('stage', 'in_progress');
            existingSla.query();
            if (existingSla.next()) return {success: true, sla_sys_id: existingSla.getUniqueValue(), message: 'SLA already running'};
            var slaGr = new GlideRecord('task_sla');
            slaGr.initialize();
            slaGr.task = incidentGr.getUniqueValue();
            slaGr.sla = slaType === 'response' ? this.getResponseSlaDefinition(priority) : this.getResolutionSlaDefinition(priority);
            slaGr.sla_type = slaType;
            slaGr.stage = 'in_progress';
            slaGr.start_time = new GlideDateTime();
            var duration = config.duration;
            var endTime = new GlideDateTime(slaGr.start_time);
            endTime.addSeconds(duration);
            slaGr.end_time = endTime;
            slaGr.business_duration = duration;
            slaGr.percentage = 0;
            var slaSysId = slaGr.insert();
            if (slaSysId) {
                var workNotes = incidentGr.getValue('work_notes') || '';
                workNotes += '\n[SLA] ' + config.name + ' (' + this.formatDuration(duration) + ') started at ' + new GlideDateTime().getDisplayValue();
                incidentGr.setValue('work_notes', workNotes);
                incidentGr.setWorkflow(false);
                incidentGr.update();
                return {success: true, sla_sys_id: slaSysId, sla_type: slaType, sla_name: config.name, duration: duration, duration_label: this.formatDuration(duration), message: config.name + ' started for ' + incidentGr.number};
            } else {
                return {success: false, error: 'Failed to create SLA record'};
            }
        } catch (e) { return {success: false, error: e.message}; }
    },
    getResponseSlaDefinition: function(priority) {
        var config = this.SLA_CONFIG.response[priority];
        if (!config) return '';
        var gr = new GlideRecord('contract_sla');
        if (gr.get('name', config.name)) return gr.getUniqueValue();
        return '';
    },
    getResolutionSlaDefinition: function(priority) {
        var config = this.SLA_CONFIG.resolution[priority];
        if (!config) return '';
        var gr = new GlideRecord('contract_sla');
        if (gr.get('name', config.name)) return gr.getUniqueValue();
        return '';
    },
    stopAllSlas: function(incidentGr) { return this.stopSlas(incidentGr, null); },
    stopSlas: function(incidentGr, slaType) {
        if (!incidentGr) return false;
        try {
            var gr = new GlideRecord('task_sla');
            gr.addQuery('task', incidentGr.getUniqueValue());
            gr.addQuery('stage', 'in_progress');
            if (slaType) gr.addQuery('sla_type', slaType);
            gr.query();
            var stopped = 0;
            while (gr.next()) {
                gr.stage = 'completed';
                gr.completion_time = new GlideDateTime();
                gr.has_breached = false;
                gr.percentage = 100;
                gr.update();
                stopped++;
            }
            if (stopped > 0) gs.info('SLAUtils: Stopped ' + stopped + ' SLA(s) for incident ' + incidentGr.number);
            return true;
        } catch (e) { return false; }
    },
    sendSlaNotification: function(incidentGr, slaType, percentageCompleted) {
        if (!incidentGr) return;
        try {
            var eventName = '';
            if (percentageCompleted >= 100) eventName = 'sla.breached';
            else if (percentageCompleted >= 90) eventName = 'sla.90_percent';
            else if (percentageCompleted >= 75) eventName = 'sla.75_percent';
            if (eventName) gs.eventQueue(eventName, incidentGr, slaType, '');
        } catch (e) {}
    },
    processPendingNotifications: function() {
        var count = 0;
        var now = new GlideDateTime();
        var gr = new GlideRecord('task_sla');
        gr.addQuery('stage', 'in_progress');
        gr.query();
        while (gr.next()) {
            var duration = parseInt(gr.getValue('business_duration')) || 3600;
            var lastNotified = parseInt(gr.getValue('u_last_notified_percentage') || 0);
            var grInc = new GlideRecord('incident');
            if (!grInc.get(gr.getValue('task'))) continue;
            var startTime = new GlideDateTime(gr.getValue('start_time'));
            var elapsed = GlideDateTime.subtract(startTime, now);
            var elapsedStr = elapsed.getDisplayValue();
            var parts = elapsedStr.split(':');
            var elapsedSeconds = parts.length === 3 ? parseInt(parts[0])*3600 + parseInt(parts[1])*60 + parseFloat(parts[2]) : 0;
            var percentage = Math.round((elapsedSeconds / duration) * 100);
            gr.percentage = percentage;
            if (percentage >= 100 && lastNotified < 100) {
                gr.has_breached = true; gr.stage = 'completed'; gr.completion_time = now; gr.u_last_notified_percentage = 100;
                this.sendSlaNotification(grInc, gr.getValue('sla_type'), 100); count++;
            } else if (percentage >= 90 && lastNotified < 90) {
                gr.u_last_notified_percentage = 90; this.sendSlaNotification(grInc, gr.getValue('sla_type'), 90); count++;
            } else if (percentage >= 75 && lastNotified < 75) {
                gr.u_last_notified_percentage = 75; this.sendSlaNotification(grInc, gr.getValue('sla_type'), 75); count++;
            }
            gr.setWorkflow(false); gr.update();
        }
        return count;
    },
    type: 'SLAUtils'
};

sys_script.script:
(function executeRule(current, previous /*null when async*/) {
    if (current.assignment_group.nil()) {
        var assigner = new ITSMGroupAssignment();
        var assigned = assigner.assignL1Group(current);
        if (assigned) {
            var notif = new ITSMNotificationUtils();
            notif.sendAssignedNotification(current, '');
        }
    }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    if (current.u_escalate_to_l2 == true) {
        var assigner = new ITSMGroupAssignment();
        var escalated = assigner.escalateToL2(current);
        if (escalated) {
            var notif = new ITSMNotificationUtils();
            notif.sendEscalationNotification(current);
            notif.sendAssignedNotification(current, previous.getValue('assignment_group'));
            current.work_notes = '*** INCIDENT ESCALATED TO L2 ***\nEscalated by: ' + gs.getUserDisplayName() + '\nPrevious L1 Group: ' + previous.getDisplayValue('assignment_group');
            current.u_escalate_to_l2 = false;
        }
    }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var notif = new ITSMNotificationUtils();
    notif.sendStateChangeNotification(current, previous.getValue('state'));
    if (current.assignment_group.changes()) {
        notif.sendAssignedNotification(current, previous.getValue('assignment_group'));
    }
    if (current.state == 6) gs.info('Incident ' + current.number + ' has been resolved');
    if (current.state == 7) gs.info('Incident ' + current.number + ' has been closed');
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    if (gs.hasRole('itsm_l1_agent') && !gs.hasRole('admin')) {
        var userGroups = [];
        var groupMember = new GlideRecord('sys_user_grmember');
        groupMember.addQuery('user', gs.getUserID());
        groupMember.query();
        while (groupMember.next()) userGroups.push(groupMember.getValue('group'));
        if (userGroups.length > 0) {
            current.addQuery('assignment_group', 'IN', userGroups.join(','));
        } else {
            current.addQuery('sys_id', '-1');
        }
    }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var pu = new ProblemUtils();
    pu.sendProblemStateChangeNotification(current, previous.getValue('state'));
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var cu = new ChangeUtils();
    if (!cu.isInfrastructureChange(current)) return;
    var currentState = current.getValue('state');
    var previousState = previous ? previous.getValue('state') : null;
    if (!previous && currentState === '1') { current.state = 2; }
    if (currentState === '4' && previousState !== '4') { cu.autoCreateChangeTasks(current); }
    if (cu.isHighPriority(current) && (!current.cab_required || current.cab_required === 'false')) {
        cu.setCABForChange(current);
    }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var cu = new ChangeUtils();
    cu.sendChangeStateChangeNotification(current, previous.getValue('state'));
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var kbGr = new GlideRecord('kb_knowledge_base');
    if (!kbGr.get(current.getValue('kb_knowledge_base'))) return;
    if (kbGr.getValue('name') !== 'Technical Knowledge Base') return;
    var newState = current.getValue('workflow_state');
    if (newState !== 'published') return;
    var oldState = previous ? previous.getValue('workflow_state') : '';
    if (oldState === 'published') return;
    if (gs.hasRole('admin') || gs.hasRole('knowledge_manager') || gs.hasRole('knowledge_admin')) return;
    current.setValue('workflow_state', 'pending_approval');
    current.work_notes = (current.work_notes || '') + '\n[System] Publication requires approval. Article moved to Pending Approval state.';
    gs.eventQueue('knowledge.article.pending_approval', current, current.getValue('kb_knowledge_base'), 'Article ' + current.number + ' requires approval to publish');
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var kbGr = new GlideRecord('kb_knowledge_base');
    if (!kbGr.get(current.getValue('kb_knowledge_base'))) return;
    if (kbGr.getValue('name') !== 'Employee Knowledge Base') return;
    if (current.isNewRecord() && !previous) {
        current.setValue('workflow_state', 'published');
    }
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var slaUtils = new SLAUtils();
    slaUtils.startResponseSla(current);
    slaUtils.startResolutionSla(current);
})(current, previous);

(function executeRule(current, previous /*null when async*/) {
    var currentState = current.getValue('state');
    var previousState = previous ? previous.getValue('state') : null;
    if (currentState === previousState) return;
    var slaUtils = new SLAUtils();
    if (currentState === '6' || currentState === '7') { slaUtils.stopAllSlas(current); }
    if (previousState && (previousState === '6' || previousState === '7') && currentState !== '6' && currentState !== '7') {
        slaUtils.startResponseSla(current);
        slaUtils.startResolutionSla(current);
    }
})(current, previous);

sys_security_acl.script:
(function evaluateRule(current, table) {
    if (current && gs.hasRole('itsm_l1_agent') && !gs.hasRole('admin')) {
        var userGroups = [];
        var gr = new GlideRecord('sys_user_grmember');
        gr.addQuery('user', gs.getUserID());
        gr.query();
        while (gr.next()) userGroups.push(gr.getValue('group'));
        var assignGrp = current.getValue('assignment_group');
        for (var i = 0; i < userGroups.length; i++) {
            if (userGroups[i] === assignGrp) return true;
        }
        return false;
    }
    return true;
})(current, table);

(function evaluateRule(current, table) {
    if (gs.hasRole('admin')) return true;
    var kbName = '';
    if (current) {
        var kbGr = new GlideRecord('kb_knowledge_base');
        if (kbGr.get(current.getValue('kb_knowledge_base'))) kbName = kbGr.getValue('name');
    }
    if (kbName === 'Employee Knowledge Base') return true;
    return (gs.hasRole('itsm_l1_agent') || gs.hasRole('itsm_l2_agent') || gs.hasRole('itsm_l3_agent') || gs.hasRole('knowledge_admin') || gs.hasRole('knowledge_manager'));
})(current, table);

(function evaluateRule(current, table) {
    if (gs.hasRole('admin')) return true;
    if (!current) return false;
    var kbGr = new GlideRecord('kb_knowledge_base');
    if (kbGr.get('name', 'Employee Knowledge Base')) {
        var kbSysId = kbGr.getUniqueValue();
        if (current.getValue('kb_knowledge_base') === kbSysId) return true;
    }
    return false;
})(current, table);

sysauto_script.script:
(function execute() {
    var slaUtils = new SLAUtils();
    var notificationsSent = slaUtils.processPendingNotifications();
    if (notificationsSent > 0) {
        gs.info('SLA Scheduled Job: Sent ' + notificationsSent + ' SLA notification(s)');
    }
})();
